public static boolean solve(long[] nums) {
    int n = nums.length;
    for (int p = 1; p <= n - 3; p++) {
        for (int q = p + 1; q <= n - 2; q++) {
            // Check first part: 0...p is strictly increasing
            boolean first = true;
            for (int i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    first = false;
                    break;
                }
            }
            if (!first) continue;
            // Check second part: p...q is strictly decreasing
            boolean second = true;
            for (int i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    second = false;
                    break;
                }
            }
            if (!second) continue;
            // Check third part: q...n-1 is strictly increasing
            boolean third = true;
            for (int i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    third = false;
                    break;
                }
            }
            if (third) {
                return true;
            }
        }
    }
    return false;
}

